import React, { useState, useEffect } from "react";
import axios from "axios";

function App() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState("");
  const [history, setHistory] = useState([]);

  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [token, setToken] = useState(localStorage.getItem("token"));

  const API = "http://127.0.0.1:8000";

  // =====================
  // LOGIN
  // =====================
  const handleLogin = async () => {
    try {
      const res = await axios.post(`${API}/login`, null, {
        params: { username, password }
      });

      localStorage.setItem("token", res.data.access_token);
      setToken(res.data.access_token);

      alert("Login Success ✅");
      fetchHistory(res.data.access_token);
    } catch (err) {
      alert("Login Failed ❌");
    }
  };

  // =====================
  // REGISTER
  // =====================
  const handleRegister = async () => {
    try {
      await axios.post(`${API}/register`, null, {
        params: { username, password }
      });

      alert("Registered Successfully ✅");
    } catch {
      alert("Error");
    }
  };

  // =====================
  // FILE UPLOAD
  // =====================
  const handleUpload = (e) => {
    setFile(e.target.files[0]);
  };

  // =====================
  // PREDICT (IMPORTANT)
  // =====================
  const handlePredict = async () => {
    if (!file) return alert("Upload file first");

    const formData = new FormData();
    formData.append("file", file);

    try {
      const res = await axios.post(`${API}/predict`, formData, {
        headers: {
          Authorization: `Bearer ${token}`   // 🔥 IMPORTANT LINE
        }
      });

      setResult(res.data.blood_group);
      fetchHistory(token);
    } catch (err) {
      alert("Prediction failed ❌");
    }
  };

  // =====================
  // FETCH HISTORY
  // =====================
  const fetchHistory = async (tok = token) => {
    try {
      const res = await axios.get(`${API}/history`, {
        headers: {
          Authorization: `Bearer ${tok}`
        }
      });

      setHistory(res.data.data);
    } catch {
      console.log("No history");
    }
  };

  // =====================
  // DOWNLOAD PDF
  // =====================
  const downloadPDF = () => {
    window.open(`${API}/download`, "_blank");
  };

  useEffect(() => {
    if (token) fetchHistory();
  }, []);

  // =====================
  // UI
  // =====================
  return (
    <div style={{
      height: "100vh",
      background: "linear-gradient(to right, #4facfe, #00f2fe)",
      display: "flex",
      justifyContent: "center",
      alignItems: "center"
    }}>
      <div style={{
        background: "white",
        padding: "30px",
        borderRadius: "15px",
        width: "400px",
        textAlign: "center"
      }}>

        <h2>🧠 Blood Group Detection</h2>

        {/* LOGIN / REGISTER */}
        {!token && (
          <>
            <input
              placeholder="Username"
              onChange={(e) => setUsername(e.target.value)}
            /><br /><br />

            <input
              type="password"
              placeholder="Password"
              onChange={(e) => setPassword(e.target.value)}
            /><br /><br />

            <button onClick={handleLogin}>Login</button>
            <button onClick={handleRegister}>Register</button>
          </>
        )}

        {/* AFTER LOGIN */}
        {token && (
          <>
            <input type="file" onChange={handleUpload} />
            <br /><br />

            <button onClick={handlePredict}>Predict</button>
            <br /><br />

            {result && <h3>Result: {result}</h3>}

            <button onClick={downloadPDF}>Download Report</button>

            <h4>History</h4>
            {history.map((item, i) => (
              <p key={i}>
                {item.filename} → {item.prediction}
              </p>
            ))}
          </>
        )}
      </div>
    </div>
  );
}

export default App;
